def num_distinct(s: str, t: str) -> int:
    """Count distinct subsequences of s that equal t."""
    m = len(t)
    if m == 0:
        return 1
    if len(s) < m:
        return 0

    # dp[j] represents the number of ways to form t[:j] using characters seen so far
    dp = [0] * (m + 1)
    dp[0] = 1  # Empty string t can always be formed in exactly one way

    for char in s:
        # Traverse backwards to avoid using updated values in the same iteration
        for j in range(min(m, dp[0] + m), 0, -1):
            if char == t[j - 1]:
                dp[j] += dp[j - 1]

    return dp[m]
